import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import API from '../services/axios';

const FLOWER_CSS = `
  @keyframes floatA { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-14px) rotate(12deg)} }
  @keyframes floatB { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-9px) rotate(-9deg)} }
  @keyframes floatC { 0%,100%{transform:translateY(0) rotate(0deg)} 50%{transform:translateY(-18px) rotate(18deg)} }
`;

function ConfirmModal({ message, subtext, onConfirm, onCancel, confirmLabel, icon }) {
  return (
    <div style={{ position: 'fixed', inset: 0, background: 'rgba(45,31,31,0.6)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 9999, padding: '1rem' }}>
      <div style={{ background: 'white', borderRadius: '24px', padding: '2.5rem', maxWidth: '400px', width: '100%', textAlign: 'center', boxShadow: '0 30px 60px rgba(45,31,31,0.3)', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', top: '12px', left: '16px', fontSize: '1.2rem', opacity: 0.2 }}>🌸</div>
        <div style={{ position: 'absolute', top: '12px', right: '16px', fontSize: '1.2rem', opacity: 0.2 }}>🌺</div>
        <div style={{ position: 'absolute', bottom: '12px', left: '16px', fontSize: '1rem', opacity: 0.15 }}>🌼</div>
        <div style={{ position: 'absolute', bottom: '12px', right: '16px', fontSize: '1rem', opacity: 0.15 }}>🌷</div>
        <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>{icon}</div>
        <h2 style={{ color: '#2d1f1f', fontWeight: '700', fontSize: '1.3rem', marginBottom: '0.5rem', fontFamily: "'Cormorant Garamond', serif" }}>{message}</h2>
        <p style={{ color: '#a08880', fontSize: '0.88rem', marginBottom: '2rem', lineHeight: '1.6' }}>{subtext}</p>
        <div style={{ display: 'flex', gap: '12px' }}>
          <button onClick={onCancel} style={{ flex: 1, padding: '12px', background: '#f5e8e3', color: '#a08880', border: 'none', borderRadius: '14px', cursor: 'pointer', fontWeight: '600', fontSize: '0.88rem', fontFamily: "'DM Sans', sans-serif" }}>Go Back</button>
          <button onClick={onConfirm} style={{ flex: 2, padding: '12px', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '14px', cursor: 'pointer', fontWeight: '700', fontSize: '0.88rem', fontFamily: "'DM Sans', sans-serif", boxShadow: '0 4px 14px rgba(201,169,154,0.4)' }}>{confirmLabel}</button>
        </div>
      </div>
    </div>
  );
}

function Register() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const handleSubmitClick = (e) => {
    e.preventDefault();
    setError('');
    if (form.password !== form.confirmPassword) { setError('Passwords do not match!'); return; }
    if (form.password.length < 6) { setError('Password must be at least 6 characters.'); return; }
    setShowConfirm(true);
  };

  const handleConfirmRegister = async () => {
    setShowConfirm(false);
    setLoading(true);
    try {
      const res = await API.post('/auth/signup', { name: form.name, email: form.email, password: form.password });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('user', JSON.stringify(res.data.user));
      navigate('/home');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Try again.');
    } finally { setLoading(false); }
  };

  return (
    <div style={{
      position: 'fixed',
      inset: 0,
      overflow: 'hidden',
      background: 'linear-gradient(135deg, #fdf6f3 0%, #f9ede8 50%, #f5e0d8 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      padding: '1rem',
      fontFamily: "'DM Sans', sans-serif",
    }}>
      <style>{FLOWER_CSS}</style>

      {/* Background flowers */}
      {[
        { f: '🌸', t: '5%',  l: '92%', a: 'floatA', d: '4s',   op: 0.18 },
        { f: '🌺', t: '12%', l: '2%',  a: 'floatB', d: '5s',   op: 0.15 },
        { f: '🌼', t: '78%', l: '94%', a: 'floatC', d: '6s',   op: 0.12 },
        { f: '🌷', t: '82%', l: '3%',  a: 'floatA', d: '4.5s', op: 0.14 },
        { f: '💮', t: '45%', l: '96%', a: 'floatB', d: '3.8s', op: 0.10 },
        { f: '🌺', t: '40%', l: '1%',  a: 'floatC', d: '5.5s', op: 0.11 },
      ].map((fl, i) => (
        <span key={i} style={{ position: 'absolute', top: fl.t, left: fl.l, fontSize: '1.8rem', opacity: fl.op, animation: `${fl.a} ${fl.d} ease-in-out infinite`, animationDelay: `${i * 0.4}s`, pointerEvents: 'none' }}>{fl.f}</span>
      ))}

      {showConfirm && (
        <ConfirmModal
          icon="🚀"
          message="Create Your Account?"
          subtext={`Welcome ${form.name}! You're about to join EventHub with ${form.email}`}
          confirmLabel="Yes, Create Account 🌸"
          onConfirm={handleConfirmRegister}
          onCancel={() => setShowConfirm(false)}
        />
      )}

      {/* Main Card */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', maxWidth: '860px', width: '100%', borderRadius: '28px', overflow: 'hidden', boxShadow: '0 30px 80px rgba(201,169,154,0.3)', border: '1px solid #f0ddd7', position: 'relative', zIndex: 1 }}>

        {/* Left panel - form */}
        <div style={{ background: '#fffaf8', padding: '2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
          <div style={{ position: 'absolute', bottom: '10px', right: '14px', fontSize: '1.2rem', opacity: 0.12, pointerEvents: 'none' }}>🌷</div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '1.5rem' }}>
            <div style={{ width: '34px', height: '34px', background: 'linear-gradient(135deg, #c9a99a, #e8c4b8)', borderRadius: '9px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem' }}>🌸</div>
            <span style={{ fontWeight: '700', fontSize: '1.1rem', color: '#2d1f1f', fontFamily: "'Cormorant Garamond', serif" }}>Event<span style={{ color: '#c9a99a' }}>Hub</span></span>
          </div>

          <h1 style={{ color: '#2d1f1f', fontSize: '1.7rem', fontWeight: '700', marginBottom: '0.3rem', fontFamily: "'Cormorant Garamond', serif" }}>Create Account</h1>
          <p style={{ color: '#a08880', fontSize: '0.84rem', marginBottom: '1.2rem' }}>Join our lovely community 🌷</p>

          {error && (
            <div style={{ background: '#fdeee9', border: '1px solid #f0c4b8', color: '#a05040', padding: '10px 14px', borderRadius: '10px', marginBottom: '1rem', fontSize: '0.82rem' }}>
              ⚠️ {error}
            </div>
          )}

          <form onSubmit={handleSubmitClick}>
            {/* Full Name */}
            <div style={{ marginBottom: '0.85rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '6px' }}>FULL NAME</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '13px', top: '50%', transform: 'translateY(-50%)', fontSize: '0.85rem' }}>👤</span>
                <input type="text" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} required placeholder="Your name"
                  style={{ width: '100%', padding: '11px 13px 11px 40px', background: 'white', border: '1.5px solid #f0ddd7', borderRadius: '11px', color: '#2d1f1f', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            {/* Email */}
            <div style={{ marginBottom: '0.85rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '6px' }}>EMAIL ADDRESS</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '13px', top: '50%', transform: 'translateY(-50%)', fontSize: '0.85rem' }}>✉️</span>
                <input type="email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} required placeholder="you@example.com"
                  style={{ width: '100%', padding: '11px 13px 11px 40px', background: 'white', border: '1.5px solid #f0ddd7', borderRadius: '11px', color: '#2d1f1f', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            {/* Password */}
            <div style={{ marginBottom: '0.85rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '6px' }}>PASSWORD</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '13px', top: '50%', transform: 'translateY(-50%)', fontSize: '0.85rem' }}>🔑</span>
                <input type="password" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required placeholder="Min 6 characters"
                  style={{ width: '100%', padding: '11px 13px 11px 40px', background: 'white', border: '1.5px solid #f0ddd7', borderRadius: '11px', color: '#2d1f1f', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            {/* Confirm Password */}
            <div style={{ marginBottom: '1rem' }}>
              <label style={{ display: 'block', color: '#6b5a55', fontSize: '0.74rem', fontWeight: '600', marginBottom: '6px' }}>CONFIRM PASSWORD</label>
              <div style={{ position: 'relative' }}>
                <span style={{ position: 'absolute', left: '13px', top: '50%', transform: 'translateY(-50%)', fontSize: '0.85rem' }}>✅</span>
                <input type="password" value={form.confirmPassword} onChange={e => setForm({ ...form, confirmPassword: e.target.value })} required placeholder="Repeat password"
                  style={{ width: '100%', padding: '11px 13px 11px 40px', background: 'white', border: '1.5px solid #f0ddd7', borderRadius: '11px', color: '#2d1f1f', fontSize: '0.87rem', outline: 'none', boxSizing: 'border-box' }}
                  onFocus={e => e.target.style.borderColor = '#c9a99a'} onBlur={e => e.target.style.borderColor = '#f0ddd7'} />
              </div>
            </div>

            <button type="submit" disabled={loading} style={{ width: '100%', padding: '13px', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', border: 'none', borderRadius: '11px', fontWeight: '600', fontSize: '0.92rem', cursor: loading ? 'not-allowed' : 'pointer', boxShadow: '0 6px 20px rgba(201,169,154,0.4)', opacity: loading ? 0.7 : 1, fontFamily: "'DM Sans', sans-serif" }}>
              {loading ? '✨ Creating...' : '🌸 Create Account'}
            </button>
          </form>

          <p style={{ marginTop: '1rem', textAlign: 'center', color: '#a08880', fontSize: '0.83rem' }}>
            Already have an account?{' '}
            <Link to="/login" style={{ color: '#c9a99a', fontWeight: '700', textDecoration: 'none' }}>Sign In →</Link>
          </p>
        </div>

        {/* Right panel - promo */}
        <div style={{ background: 'linear-gradient(150deg, #c9a99a 0%, #b8887a 50%, #a0706a 100%)', padding: '2.5rem', display: 'flex', flexDirection: 'column', justifyContent: 'center', position: 'relative', overflow: 'hidden' }}>
          <div style={{ position: 'absolute', top: '-50px', left: '-50px', width: '180px', height: '180px', borderRadius: '50%', background: 'rgba(255,255,255,0.1)' }} />
          {['🌸','🌺','🌼','🌷'].map((f, i) => (
            <span key={i} style={{ position: 'absolute', fontSize: '1.2rem', opacity: 0.2, top: `${10 + i * 22}%`, right: `${5 + i * 3}%`, animation: `floatB ${3.5 + i * 0.5}s ease-in-out infinite`, animationDelay: `${i * 0.3}s`, pointerEvents: 'none' }}>{f}</span>
          ))}
          <div style={{ position: 'relative' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🚀</div>
            <h2 style={{ color: 'white', fontSize: '1.8rem', fontWeight: '700', marginBottom: '0.8rem', lineHeight: '1.3', fontFamily: "'Cormorant Garamond', serif" }}>Join EventHub!</h2>
            <p style={{ color: 'rgba(255,255,255,0.75)', lineHeight: '1.7', marginBottom: '1.5rem', fontSize: '0.85rem' }}>Explore and book amazing events near you. Free forever.</p>
            {[
              { icon: '🆓', text: 'Free to join always' },
              { icon: '🔔', text: 'Event notifications' },
              { icon: '🎟️', text: 'Instant booking' },
              { icon: '💝', text: 'Exclusive deals' },
            ].map((item, i) => (
              <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '12px' }}>
                <div style={{ width: '32px', height: '32px', background: 'rgba(255,255,255,0.2)', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.85rem', flexShrink: 0 }}>{item.icon}</div>
                <span style={{ color: 'rgba(255,255,255,0.88)', fontSize: '0.82rem', fontWeight: '500' }}>{item.text}</span>
              </div>
            ))}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginTop: '1.5rem' }}>
              {[{ num: '10K+', label: 'Members' }, { num: '500+', label: 'Events' }, { num: '50K+', label: 'Tickets' }, { num: '4.9★', label: 'Rating' }].map((s, i) => (
                <div key={i} style={{ background: 'rgba(255,255,255,0.15)', borderRadius: '10px', padding: '0.8rem', textAlign: 'center' }}>
                  <p style={{ color: 'white', fontWeight: '800', fontSize: '1.1rem', margin: 0 }}>{s.num}</p>
                  <p style={{ color: 'rgba(255,255,255,0.65)', fontSize: '0.7rem', margin: 0 }}>{s.label}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
